"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[188745],{475075:e=>{e.exports=JSON.parse('{"tag":{"label":"save","permalink":"/dst-api-webdocs/docs/tags/save","allTagsPath":"/dst-api-webdocs/docs/tags","count":33,"items":[{"id":"game-scripts/prefabs/ancient_husks","title":"Ancient Husks","description":"Defines the prefab data and initialization logic for ancient husk statues, including identity-specific animations and physics properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancient_husks"},{"id":"game-scripts/components/autosaver","title":"Autosaver","description":"Manages automated world saving and synchronization across master and secondary shards in DST\'s networking model.","permalink":"/dst-api-webdocs/docs/game-scripts/components/autosaver"},{"id":"game-scripts/screens/redux/beefaloskinpresetspopup","title":"BeefaloSkinPresetsPopup","description":"Manages a UI popup for viewing, loading, and saving Beefalo skin presets per character.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/beefaloskinpresetspopup"},{"id":"game-scripts/components/chessunlocks","title":"Chessunlocks","description":"Manages locking and unlocking of chess piece sketches and associated trinkets in the Don\'t Starve Together chess minigame system.","permalink":"/dst-api-webdocs/docs/game-scripts/components/chessunlocks"},{"id":"game-scripts/prefabs/chester_eyebone","title":"Chester Eyebone","description":"Manages the state and behavior of the Chester Eyebone item, including morphing, respawning Chester, and synchronizing with its master.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chester_eyebone"},{"id":"game-scripts/fileutil","title":"Fileutil","description":"Provides utility functions for checking and erasing persistent string files, commonly used for save data or configuration cleanup.","permalink":"/dst-api-webdocs/docs/game-scripts/fileutil"},{"id":"game-scripts/prefabs/livingtree","title":"Livingtree","description":"A custom tree prefab that supports chopping, burning, and saving/loading state transitions between full tree, stump, and burnt variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/livingtree"},{"id":"game-scripts/screens/redux/manageserverslotscreen","title":"Manageserverslotscreen","description":"Displays a UI screen for managing a specific server save slot, offering options to delete, clone, convert cloud/local storage, or open the save folder.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/manageserverslotscreen"},{"id":"game-scripts/components/playbill","title":"Playbill","description":"Manages state for a theatrical playbill, tracking the current act and persisting it across save/load cycles.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playbill"},{"id":"game-scripts/components/playeravatardata","title":"Playeravatardata","description":"Manages player avatar data including name, skins, age, and equipment, with support for network replication and save/load operations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playeravatardata"},{"id":"game-scripts/playerdeaths","title":"Playerdeaths","description":"Manages persistent death logs for players, including sorting, saving, and loading historical death records.","permalink":"/dst-api-webdocs/docs/game-scripts/playerdeaths"},{"id":"game-scripts/map/retrofit_savedata","title":"Retrofit Savedata","description":"A utility module that applies worldgen retrofits to saved game data, updating legacy maps with new content and mechanics introduced in the Return of Them, Waterlogged, and other DLC updates.","permalink":"/dst-api-webdocs/docs/game-scripts/map/retrofit_savedata"},{"id":"game-scripts/components/savedrotation","title":"SavedRotation","description":"Persists and restores an entity\'s rotation during save/load operations, primarily for entities that must maintain orientation relative to moving platforms like boats.","permalink":"/dst-api-webdocs/docs/game-scripts/components/savedrotation"},{"id":"game-scripts/components/savedscale","title":"Savedscale","description":"Stores and restores non-default scale values for an entity\'s transform during save/load operations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/savedscale"},{"id":"game-scripts/widgets/savingindicator","title":"Savingindicator","description":"Displays a visual saving indicator with animation and text during world-saving operations.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/savingindicator"},{"id":"game-scripts/widgets/redux/serversaveslot","title":"Serversaveslot","description":"Renders a UI slot representing a saved server world in the server management screens, displaying metadata and enabling navigation or deletion.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/serversaveslot"},{"id":"game-scripts/screens/redux/serverslotscreen","title":"Serverslotscreen","description":"Manages the server selection screen UI, displaying existing save slots, filtering/sorting options, and handling user interactions for joining or creating new game instances.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/serverslotscreen"},{"id":"game-scripts/components/shard_autosaver","title":"Shard Autosaver","description":"Synchronizes snapshot state between the master shard and shard instances for world autosave coordination.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shard_autosaver"},{"id":"game-scripts/shardindex","title":"Shardindex","description":"Manages persistent world, server, and session data for a game shard, including loading, saving, upgrades, and world generation overrides.","permalink":"/dst-api-webdocs/docs/game-scripts/shardindex"},{"id":"game-scripts/shardsaveindex","title":"Shardsaveindex","description":"Manages shard-specific save index data and slot-level world/session metadata for persistent storage across game sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/shardsaveindex"},{"id":"game-scripts/components/shardtransactionsteps","title":"Shardtransactionsteps","description":"Manages multi-step shard-to-shard transaction lifecycle to safely transfer data and items between game shards and save states.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shardtransactionsteps"},{"id":"game-scripts/widgets/snapshottab","title":"Snapshottab","description":"Displays and manages snapshots for a specific save slot in the server admin UI, allowing users to view, scroll through, and restore game states from stored snapshots.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/snapshottab"},{"id":"game-scripts/components/timer","title":"Timer","description":"Manages named timers attached to an entity, supporting start, stop, pause, resume, and save/load operations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/timer"},{"id":"game-scripts/components/touchstonetracker","title":"Touchstonetracker","description":"Tracks which touchstones have been used by the player and persists this data across sessions and shards.","permalink":"/dst-api-webdocs/docs/game-scripts/components/touchstonetracker"},{"id":"game-scripts/components/transformer","title":"Transformer","description":"Manages switching an entity between two prefabs based on events or world state, preserving component and prefab data across transformations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/transformer"},{"id":"game-scripts/components/undertile","title":"Undertile","description":"Manages a data grid representing the tile types directly beneath map tiles, used for layered terrain storage in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/undertile"},{"id":"game-scripts/components/uniqueprefabids","title":"Uniqueprefabids","description":"Generates and tracks unique numeric IDs per prefab name to ensure distinct identification for spawned entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/uniqueprefabids"},{"id":"game-scripts/components/vaultroom","title":"Vaultroom","description":"Manages loading, saving, unloading, and layout of procedural vault rooms in the world map.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vaultroom"},{"id":"game-scripts/components/werebeast","title":"Werebeast","description":"Manages werebeast transformation logic, including moon phase triggers, manual transformation, and automatic reversion timers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/werebeast"},{"id":"game-scripts/components/wintertreegiftable","title":"Wintertreegiftable","description":"Tracks the last cycle on which a gift was given to a winter tree to enforce cooldown logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wintertreegiftable"},{"id":"game-scripts/worldentities","title":"Worldentities","description":"Provides a utility function to ensure required world-level entities (e.g., pocket dimension containers) are initialized during world save load.","permalink":"/dst-api-webdocs/docs/game-scripts/worldentities"},{"id":"game-scripts/components/worldroutes","title":"Worldroutes","description":"Stores and manages cached static route data for circular paths across the world\'s traversable terrain.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldroutes"},{"id":"game-scripts/components/yotb_stagemanager","title":"Yotb Stagemanager","description":"Manages the lifecycle and state of contest stages in a structured world progression system, including stage registration, contest activation, and save/load synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/yotb_stagemanager"}],"unlisted":false}}')}}]);